VALUES (473, 'cost-pinggu', 'masterGrid', 'COLUMN_OVERRIDE', '[{"columnName":"DOCID","visible":true,"editable":false},{"columnName":"GOODSID","visible":true,"editable":false},{"columnName":"GOODSNAME","visible":true,"editable":true,"searchable":true},{"columnName":"GOODSNAME_EN","visible":true,"editable":true},{"columnName":"STRENGTH","visible":true,"editable":true},{"columnName":"CUSTOMID","visible":true,"editable":false},{"columnName":"CUSTOMNAME","visible":true,"editable":true,"searchable":true},{"columnName":"COUNTRY","visible":true,"editable":true},{"columnName":"TRANPOSID","visible":true,"editable":false},{"columnName":"LIVERY","visible":true,"editable":true},{"columnName":"PROJECTNO","visible":true,"editable":true},{"columnName":"APEX_PL","visible":true,"editable":true},{"columnName":"ANNUAL_QTY","visible":true,"editable":true},{"columnName":"YIELD","visible":true,"editable":true},{"columnName":"P_PERPACK","visible":true,"editable":true},{"columnName":"M_PERPACK","visible":true,"editable":true},{"columnName":"S_PERBACK","visible":true,"editable":true},{"columnName":"X_PERBACK","visible":true,"editable":true},{"columnName":"PACKTYPE","visible":true,"editable":true},{"columnName":"TOTAL_YL","visible":true,"editable":false},{"columnName":"TOTAL_FL","visible":true,"editable":false},{"columnName":"TOTAL_BC","visible":true,"editable":false},{"columnName":"TOTAL_COST","visible":true,"editable":false},{"columnName":"OUT_PRICE_RMB","visible":true,"editable":true},{"columnName":"SALEMONEY","visible":true,"editable":false},{"columnName":"JGF_BATCH","visible":true,"editable":false},{"columnName":"COST_PERQP","visible":true,"editable":true},{"columnName":"COST_PERBOX","visible":true,"editable":false},{"columnName":"JGF_PERQP","visible":true,"editable":false},{"columnName":"ML_PERQP","visible":true,"editable":false},{"columnName":"Y_JG_RE","visible":true,"editable":false},{"columnName":"Y_ML","visible":true,"editable":false},{"columnName":"Y_SALE","visible":true,"editable":false},{"columnName":"FMNAME","visible":true,"editable":true},{"columnName":"FMRATE","visible":true,"editable":true},{"columnName":"MEMO","visible":true,"editable":true}]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (474, 'cost-pinggu', 'masterGrid', 'VALIDATION', '[]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (475, 'cost-pinggu', 'masterGrid', 'CALC', '[
  {"field":"SALEMONEY","expression":"CostPinggu.OUT_PRICE_RMB / CostPinggu.P_PERPACK * CostPinggu.APEX_PL * (CostPinggu.YIELD / 100)","triggerFields":["CostPinggu.OUT_PRICE_RMB","CostPinggu.P_PERPACK","CostPinggu.APEX_PL","CostPinggu.YIELD"]},
  {"field":"JGF_BATCH","expression":"CostPinggu.SALEMONEY - CostPinggu.TOTAL_COST","triggerFields":["CostPinggu.SALEMONEY","CostPinggu.TOTAL_COST"]},
  {"field":"COST_PERBOX","expression":"CostPinggu.TOTAL_COST / CostPinggu.APEX_PL * CostPinggu.P_PERPACK","triggerFields":["CostPinggu.TOTAL_COST","CostPinggu.APEX_PL","CostPinggu.P_PERPACK"]},
  {"field":"JGF_PERQP","expression":"CostPinggu.JGF_BATCH / CostPinggu.APEX_PL * 1000","triggerFields":["CostPinggu.JGF_BATCH","CostPinggu.APEX_PL"]},
  {"field":"ML_PERQP","expression":"CostPinggu.JGF_PERQP - CostPinggu.COST_PERQP","triggerFields":["CostPinggu.JGF_PERQP","CostPinggu.COST_PERQP"]},
  {"field":"Y_JG_RE","expression":"CostPinggu.JGF_PERQP / 1000 * CostPinggu.ANNUAL_QTY","triggerFields":["CostPinggu.JGF_PERQP","CostPinggu.ANNUAL_QTY"]},
  {"field":"Y_ML","expression":"CostPinggu.ML_PERQP / 1000 * CostPinggu.ANNUAL_QTY","triggerFields":["CostPinggu.ML_PERQP","CostPinggu.ANNUAL_QTY"]},
  {"field":"Y_SALE","expression":"CostPinggu.ANNUAL_QTY / CostPinggu.P_PERPACK * CostPinggu.OUT_PRICE_RMB * CostPinggu.YIELD","triggerFields":["CostPinggu.ANNUAL_QTY","CostPinggu.P_PERPACK","CostPinggu.OUT_PRICE_RMB","CostPinggu.YIELD"]},
  {"field":"TOTAL_YL","expression":"SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"]},
  {"field":"TOTAL_FL","expression":"SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''辅料''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"],"order":9},
  {"field":"TOTAL_BC","expression":"SUM_IF(''CostPackage.COST_BATCH'', \"CostPackage.DTL_USEFLAG == ''印字包材'' || CostPackage.DTL_USEFLAG == ''非印字包材''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostPackage.COST_BATCH","CostPackage.DTL_USEFLAG","CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"],"order":10},
  {"field":"TOTAL_COST","expression":"CostPinggu.TOTAL_YL + CostPinggu.TOTAL_FL + CostPinggu.TOTAL_BC","triggerFields":["CostPinggu.TOTAL_YL","CostPinggu.TOTAL_FL","CostPinggu.TOTAL_BC"],"order":11}
]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

