INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (480, 'cost-pinggu', 'material', 'CALC', '[
  {"field":"BATCH_QTY","formulaField":"CostMaterial.GOODSNAME","formulas":{"__branch_0":{"key":"胶囊","expression":"CostPinggu.APEX_PL / 10000 * (1 + CostMaterial.EXADD_MATER / 100)","triggerFields":["CostPinggu.APEX_PL","CostMaterial.EXADD_MATER"],"matchType":"regex"},"__branch_1":{"key":"^(?!.*胶囊).*$","expression":"CostMaterial.PER_HL * CostPinggu.APEX_PL * (1 + CostMaterial.EXADD_MATER / 100) / 1000000","triggerFields":["CostMaterial.PER_HL","CostPinggu.APEX_PL","CostMaterial.EXADD_MATER"],"matchType":"regex"}}},
  {"field":"COST_BATCH","expression":"CostMaterial.BATCH_QTY * CostMaterial.PRICE","triggerFields":["CostMaterial.BATCH_QTY","CostMaterial.PRICE"]}
]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

