INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (484, 'cost-pinggu', 'package', 'CALC', '[
  {"field":"COST_BATCH","expression":"CostPackage.BATCH_QTY * CostPackage.PRICE","triggerFields":["CostPackage.BATCH_QTY","CostPackage.PRICE"]},
  {"field":"BATCH_QTY","formulaField":"CostPackage.GOODSNAME","formulas":{"__branch_0":{"key":"桶|说明书|小盒|标签|瓶|盖","expression":"CostPinggu.APEX_PL / CostPinggu.P_PERPACK * (1 + CostPackage.EXADD_MATER / 100)","triggerFields":["CostPinggu.APEX_PL","CostPinggu.P_PERPACK","CostPackage.EXADD_MATER"],"matchType":"regex"},"__branch_1":{"key":"硬片|铝箔|复合膜","expression":"CostPackage.PER_HL * CostPinggu.APEX_PL * (1 + CostPackage.EXADD_MATER / 100) / 1000000","triggerFields":["CostPackage.PER_HL","CostPinggu.APEX_PL","CostPackage.EXADD_MATER"],"matchType":"regex"},"__branch_2":{"key":"大纸箱","expression":"ceil(CostPinggu.APEX_PL / (CostPinggu.P_PERPACK * CostPinggu.S_PERBACK) * (1 + CostPackage.EXADD_MATER / 100))","triggerFields":["CostPinggu.APEX_PL","CostPinggu.P_PERPACK","CostPinggu.S_PERBACK","CostPackage.EXADD_MATER"],"matchType":"regex"},"__branch_3":{"key":"托盘","expression":"ceil(CostPinggu.APEX_PL / (CostPinggu.P_PERPACK * CostPinggu.S_PERBACK * CostPinggu.X_PERBACK) * (1 + CostPackage.EXADD_MATER / 100))","triggerFields":["CostPinggu.APEX_PL","CostPinggu.P_PERPACK","CostPinggu.S_PERBACK","CostPinggu.X_PERBACK","CostPackage.EXADD_MATER"],"matchType":"regex"},"__branch_4":{"key":"中盒","expression":"ceil(CostPinggu.APEX_PL / (CostPinggu.M_PERPACK * CostPinggu.S_PERBACK) * (1 + CostPackage.EXADD_MATER / 100))","triggerFields":["CostPinggu.APEX_PL","CostPinggu.M_PERPACK","CostPinggu.S_PERBACK","CostPackage.EXADD_MATER"],"matchType":"regex"}}}
]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (485, 'cost-pinggu', 'package', 'LOOKUP', '[{"columnName":"GOODSNAME","lookupCode":"costMaterial","mapping":{"GOODSID":"GOODSID","GOODSNAME":"GOODSNAME","STANDARDTYPE":"GOODSTYPE","PRICE":"PRICE","FACTORYNAME":"FACTORYNAME","SUQTY":"LASTSUQTY"}}]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');
